// Context (by name) for identifiers + size
const ctx = $('Merge Context').first().json;

// Grab the raw text GPT returned (OpenAI Responses API structure)
let raw;
try {
  raw = $input.first().json.output[0].content[0].text;
} catch (e) {
  throw new Error('Could not find AI response text — OpenAI output structure was unexpected.');
}

// Strip markdown fences if GPT adds them
const cleaned = (raw || '').replace(/```json/gi, '').replace(/```/g, '').trim();

// Parse JSON — fail clearly if GPT returned garbage
let out;
try {
  out = JSON.parse(cleaned);
} catch (e) {
  throw new Error('AI did not return valid JSON. Raw start: ' + cleaned.slice(0, 200));
}

// Validate the engineered image prompt
if (!out.image_prompt || typeof out.image_prompt !== 'string') {
  throw new Error('image_prompt missing or not a string.');
}

return [{
  json: {
    slot_id: ctx.slot_id,
    business_id: ctx.business_id,
    platform: ctx.platform,
    image_size: ctx.image_size,
    image_prompt: out.image_prompt
  }
}];

// Identifiers/prompt come from Parse Image Prompt
const meta = $('Parse Image Prompt').first().json;
const img = $('Generate Image').first().json || {};

// gpt-image-1 returns base64 (now turned into binary by 'Image to File').
// DALL-E would return a url. Be robust to either.
const imageUrl = img.url
  || (Array.isArray(img.data) && img.data[0] && img.data[0].url)
  || null;
const hasB64 = Array.isArray(img.data) && img.data[0] && !!img.data[0].b64_json;

return [{
  json: {
    success: true,
    slot_id: meta.slot_id,
    platform: meta.platform,
    image_size: meta.image_size,
    image_prompt: meta.image_prompt,
    image_url: imageUrl,
    image_returned_as: imageUrl ? 'url' : (hasB64 ? 'base64 (binary preview in Image to File node)' : 'unknown — inspect Generate Image output')
  }
}];
